import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as e,e as s}from"./app-be253e4c.js";const t={},o=s(`<h1 id="dockerfile" tabindex="-1"><a class="header-anchor" href="#dockerfile" aria-hidden="true">#</a> Dockerfile</h1><h3 id="运行流程" tabindex="-1"><a class="header-anchor" href="#运行流程" aria-hidden="true">#</a> 运行流程</h3><ul><li>docker从基础镜像运行一个容器</li><li>执行一条指令并对容器做出修改</li><li>执行类似docker commit 的操作提交一个新的镜像层</li><li>docker再基于提交的镜像运行一个容器</li><li>执行dockerfile中的下一条指令知道所有指令都执行完成</li></ul><h3 id="常用指令" tabindex="-1"><a class="header-anchor" href="#常用指令" aria-hidden="true">#</a> 常用指令</h3><h4 id="from" tabindex="-1"><a class="header-anchor" href="#from" aria-hidden="true">#</a> FROM</h4><p>基础镜像，当前新镜像基于那个镜像，指定一个已经存在的镜像作为模板，一般第一条指令为FROM</p><h4 id="maintainer" tabindex="-1"><a class="header-anchor" href="#maintainer" aria-hidden="true">#</a> MAINTAINER</h4><p>镜像维护者的姓名和邮箱地址，表明联系方式</p><h4 id="run" tabindex="-1"><a class="header-anchor" href="#run" aria-hidden="true">#</a> RUN</h4><p>容器构建时需要运行的命令，一般有两种格式：</p><ul><li><code>shell</code>指令格式</li><li><code>exec</code>命令格式 ：RUN [&#39;参数一&#39; , &#39;参数二&#39; , ...]</li></ul><p>RUN是在执行<code>docker bulid</code>命令时候运行的</p><h4 id="expose" tabindex="-1"><a class="header-anchor" href="#expose" aria-hidden="true">#</a> EXPOSE</h4><p>当前容器需要对外暴露的端口</p><h4 id="workdir" tabindex="-1"><a class="header-anchor" href="#workdir" aria-hidden="true">#</a> WORKDIR</h4><p>指定在容器创建后，终端默认登陆后进来的工作目录，即：文件路径落脚点</p><h4 id="user" tabindex="-1"><a class="header-anchor" href="#user" aria-hidden="true">#</a> USER</h4><p>指令该镜像需要什么样的用户角色去执行，如果没有指定，就默认root用户</p><h4 id="env" tabindex="-1"><a class="header-anchor" href="#env" aria-hidden="true">#</a> ENV</h4><p>用来在构建过程中，设置镜像的环境变量 方便后面使用；</p><h4 id="add" tabindex="-1"><a class="header-anchor" href="#add" aria-hidden="true">#</a> ADD</h4><p>将宿主机目录下的文件拷贝到镜像中，并且会自动处理URL和解压tar压缩包</p><h4 id="copy" tabindex="-1"><a class="header-anchor" href="#copy" aria-hidden="true">#</a> COPY</h4><p>类似ADD保留字功能，用来拷贝文件和目录到镜像中</p><p>将从构建上下文目录中&lt;源路径&gt;的文件/目录复制到新的一层的镜像内的&lt;目标路径&gt;位置,基本过程如下：</p><ul><li>COPY src dest</li><li>COPY [&quot;src&quot; , &quot;dest&quot; ]</li><li>&lt;src源路径&gt;： 源文件或者源目录</li><li>&lt;dest目标路径&gt;：容器内的指定路径，该路径不用事先建好，如果没有会自动创建</li></ul><h4 id="volume" tabindex="-1"><a class="header-anchor" href="#volume" aria-hidden="true">#</a> VOLUME</h4><p>容器卷，可以用来实现文件的映射</p><h4 id="cmd" tabindex="-1"><a class="header-anchor" href="#cmd" aria-hidden="true">#</a> CMD</h4><p>用来指定容器启动后需要做的事情/流程，</p><p>CMD指令和RUN指令格式相似，支持两种格式：</p><ul><li>shell格式： CMD &lt;命令&gt;</li><li>exec 格式： CMD [&quot;参数一&quot; , &quot;参数二&quot; ,&quot;....&quot;]</li><li>参数列表格式： CMD [&quot;参数一&quot; , &quot;参数二&quot; , &quot;...&quot;]，在指定了ENTRYPOINT指令后，用CMD指定具体的参数</li></ul><p><strong>注意：dockerfile中可以有多个CMD指令，但是只有最后一个会生效，CMD会被docker run之后的参数/bin/bash替换掉</strong></p><p>CMD指令和RUN指令的区别：</p><ul><li>CMD命令是在docker run时运行</li><li>RUN命令是在docker build命令时运行</li></ul><h4 id="entrypoint" tabindex="-1"><a class="header-anchor" href="#entrypoint" aria-hidden="true">#</a> ENTRYPOINT</h4><p>也是用来指定一个容器启动时要运行的命令，类似CMD指令，注意传参格式</p><h3 id="构建镜像" tabindex="-1"><a class="header-anchor" href="#构建镜像" aria-hidden="true">#</a> 构建镜像</h3><p>用来构建node.js镜像，部署项目</p><div class="language-docker" data-ext="docker"><pre class="language-docker"><code>
<span class="token comment"># 安装node</span>
<span class="token instruction"><span class="token keyword">FROM</span> node:12.6.0-alpine</span>
<span class="token comment"># 标签</span>
<span class="token instruction"><span class="token keyword">LABEL</span> version=<span class="token string">&quot;Beta1.0&quot;</span></span>
<span class="token instruction"><span class="token keyword">LABEL</span> description=<span class="token string">&quot;基于egg框架实现的Oauth2统一认证登录&quot;</span></span>
<span class="token comment"># 作者</span>
<span class="token instruction"><span class="token keyword">LABEL</span> author=<span class="token string">&quot;微信公众号：储凡&quot;</span></span>
<span class="token instruction"><span class="token keyword">LABEL</span> email=<span class="token string">&quot;mmdapl@163.com&quot;</span></span>
<span class="token comment"># 创建项目空间</span>
<span class="token instruction"><span class="token keyword">RUN</span> mkdir -p /web-project/node/oauth2-service</span>
<span class="token comment"># 将当前代码文件复制到工作区域</span>
<span class="token instruction"><span class="token keyword">COPY</span> . /web-project/node/oauth2-service</span>
<span class="token comment"># 进入 vendors</span>
<span class="token instruction"><span class="token keyword">WORKDIR</span> /web-project/node/oauth2-service</span>
<span class="token comment"># 指定npm仓库</span>
<span class="token instruction"><span class="token keyword">RUN</span> npm install --registry https://registry.npm.taobao.org</span>
<span class="token comment"># 暴露端口</span>
<span class="token instruction"><span class="token keyword">EXPOSE</span> 8848</span>
<span class="token comment"># 项目启动 </span>
<span class="token instruction"><span class="token keyword">CMD</span> [<span class="token string">&quot;npm&quot;</span>,<span class="token string">&quot;run&quot;</span>,<span class="token string">&quot;start&quot;</span>]</span>

</code></pre></div>`,40),r=[o];function i(c,d){return n(),e("div",null,r)}const h=a(t,[["render",i],["__file","dockerfile.html.vue"]]);export{h as default};
